  2→import React, { useState, useEffect } from 'react';
  3→import { User } from '../types';
  4→import { Check, Download, ArrowLeft, ShieldCheck, LayoutList, History, FileText, Zap, Database, Fuel, Droplet, CreditCard, Star, Loader2, Sparkles } from 'lucide-react';
  5→import jsPDF from 'jspdf';
  6→
  7→interface PlanProps {
  8→  onBack: () => void;
  9→  user: User | null;
 10→  onUpgrade: (plan: 'free' | 'pro' | 'enterprise') => void;
 11→  initialTab?: 'my-plan' | 'pricing' | 'billing';
 12→}
 13→
 14→const Plan: React.FC<PlanProps> = ({ onBack, user, onUpgrade, initialTab = 'my-plan' }) => {
 15→  const [activeTab, setActiveTab] = useState<'my-plan' | 'pricing' | 'billing'>(initialTab);
 16→  const [isProcessing, setIsProcessing] = useState(false);
 17→
 18→  useEffect(() => {
 19→    setActiveTab(initialTab);
 20→  }, [initialTab]);
 21→
 22→  // Mock Data pour l'historique
 23→  const payments = [
 24→    { id: 'INV-2024-003', date: '01/03/2024', amount: 89.00, desc: 'Abonnement Pro (Mensuel)', status: 'Payé' },
 25→    { id: 'INV-2024-002', date: '01/02/2024', amount: 89.00, desc: 'Abonnement Pro (Mensuel)', status: 'Payé' },
 26→    { id: 'INV-2024-001', date: '15/01/2024', amount: 49.00, desc: 'Pack GTO Gas (La Pompe)', status: 'Payé' },
 27→  ];
 28→
 29→  const plans = [
 30→    {
 31→      id: 'free',
 32→      name: 'Starter',
 33→      price: 0,
 34→      period: '/mois',
 35→      icon: <Droplet size={24} />,
 36→      features: ['1 Projet Actif / mois', 'Audit manuel', 'Support communauté'],
 37→      cta: 'Plan Actuel',
 38→      current: user?.plan === 'free'
 39→    },
 40→    {
 41→      id: 'pro',
 42→      name: 'Pro',
 43→      price: 89,
 44→      period: '/mois',
 45→      icon: <Fuel size={24} />,
 46→      popular: true,
 47→      features: ['Indexation IA', '3 Projets Actifs / mois', 'Monitoring Continu', 'Support Prioritaire', 'API Access (Beta)', 'Rapports PDF marque blanche'],
 48→      cta: 'Passer Pro',
 49→      current: user?.plan === 'pro'
 50→    },
 51→    {
 52→      id: 'enterprise',
 53→      name: 'Agency',
 54→      price: 299,
 55→      period: '/mois',
 56→      icon: <Database size={24} />,
 57→      features: ['Indexation IA', 'Projets illimités', 'Dedicated Account Manager', 'API Full Access', 'SSO & Sécurité avancée', 'Formation AEO équipe'],
 58→      cta: 'Contacter Ventes',
 59→      current: user?.plan === 'enterprise'
 60→    }
 61→  ];
 62→
 63→  const handleUpgradeClick = (planId: string) => {
 64→    if (planId === 'enterprise') {
 65→        window.location.href = "mailto:sales@citedby.ai";
 66→        return;
 67→    }
 68→    
 69→    setIsProcessing(true);
 70→    // Simulation API call
 71→    setTimeout(() => {
 72→        onUpgrade(planId as any);
 73→        setIsProcessing(false);
 74→        setActiveTab('my-plan');
 75→        alert(`Félicitations ! Vous êtes passé au plan ${planId.toUpperCase()}.`);
 76→    }, 1500);
 77→  };
 78→
 79→  const generateInvoice = (payment: typeof payments[0]) => {
 80→    if (!user) return;
 81→    const doc = new jsPDF();
 82→    
 83→    // Header
 84→    doc.setFontSize(22);
 85→    doc.setFont("helvetica", "bold");
 86→    doc.text("CitedBy.ai", 20, 20);
 87→    
 88→    doc.setFontSize(10);
 89→    doc.setFont("helvetica", "normal");
 90→    doc.text(`Facture N° ${payment.id}`, 20, 30);
 91→    doc.text(`Date : ${payment.date}`, 20, 35);
 92→
 93→    // Client Info
 94→    doc.text("Facturé à :", 140, 30);
 95→    doc.setFont("helvetica", "bold");
 96→    doc.text(user.name || "Client", 140, 35);
 97→    doc.setFont("helvetica", "normal");
 98→    doc.text(user.email || "", 140, 40);
 99→
100→    // Line Items Header
101→    doc.line(20, 55, 190, 55);
102→    doc.setFont("helvetica", "bold");
103→    doc.text("Description", 20, 62);
104→    doc.text("Montant HT", 160, 62);
105→    doc.line(20, 66, 190, 66);
106→
107→    // Item
108→    const priceHT = (payment.amount / 1.2).toFixed(2);
109→    const tva = (payment.amount - parseFloat(priceHT)).toFixed(2);
110→
111→    doc.setFont("helvetica", "normal");
112→    doc.text(payment.desc, 20, 75);
113→    doc.text(`${priceHT} €`, 160, 75);
114→
115→    // Totals
116→    doc.line(20, 90, 190, 90);
117→    doc.text("Sous-total HT :", 130, 100);
118→    doc.text(`${priceHT} €`, 160, 100);
119→    
120→    doc.text("TVA (20%) :", 130, 107);
121→    doc.text(`${tva} €`, 160, 107);
122→
123→    doc.setFont("helvetica", "bold");
124→    doc.setFontSize(12);
125→    doc.text("Total TTC :", 130, 117);
126→    doc.text(`${payment.amount.toFixed(2)} €`, 160, 117);
127→
128→    doc.setFontSize(8);
129→    doc.setFont("helvetica", "italic");
130→    doc.text("Merci de votre confiance. Paiement effectué par CB.", 20, 140);
131→
132→    doc.save(`Facture_${payment.id}.pdf`);
133→  };
134→
135→  return (
136→    <div className="max-w-6xl mx-auto px-4 py-10 animate-in fade-in duration-500 min-h-screen">
137→      <button onClick={onBack} className="flex items-center text-gray-400 hover:text-white mb-6 transition-colors">
138→        <ArrowLeft size={18} className="mr-2" /> Retour
139→      </button>
140→
141→      <div className="text-center mb-10">
142→         <h1 className="text-4xl font-serif font-bold text-white mb-4">Plan & Facturation</h1>
143→         <p className="text-gray-400 max-w-2xl mx-auto">Gérez vos informations personnelles, votre abonnement et vos préférences.</p>
144→      </div>
145→
146→      {/* Tabs Navigation */}
147→      <div className="flex justify-center mb-12">
148→        <div className="inline-flex bg-white/5 p-1.5 rounded-2xl border border-white/10">
149→          <button
150→            onClick={() => setActiveTab('my-plan')}
151→            className={`px-6 py-2.5 rounded-xl text-sm font-bold transition-all flex items-center gap-2 ${
152→              activeTab === 'my-plan' ? 'bg-primary text-black shadow-lg' : 'text-gray-400 hover:text-white'
153→            }`}
154→          >
155→            <ShieldCheck size={16} /> Mon Abonnement
156→          </button>
157→          <button
158→            onClick={() => setActiveTab('pricing')}
159→            className={`px-6 py-2.5 rounded-xl text-sm font-bold transition-all flex items-center gap-2 ${
160→              activeTab === 'pricing' ? 'bg-primary text-black shadow-lg' : 'text-gray-400 hover:text-white'
161→            }`}
162→          >
163→            <LayoutList size={16} /> Changer d'offre
164→          </button>
165→          <button
166→            onClick={() => setActiveTab('billing')}
167→            className={`px-6 py-2.5 rounded-xl text-sm font-bold transition-all flex items-center gap-2 ${
168→              activeTab === 'billing' ? 'bg-primary text-black shadow-lg' : 'text-gray-400 hover:text-white'
169→            }`}
170→          >
171→            <History size={16} /> Historique & Factures
172→          </button>
173→        </div>
174→      </div>
175→
176→      {/* TAB: MON ABONNEMENT */}
177→      {activeTab === 'my-plan' && (
178→        <div className="animate-in fade-in slide-in-from-left-4 duration-300 grid md:grid-cols-2 gap-8">
