  5→import html2canvas from 'html2canvas';
  6→import jsPDF from 'jspdf';
  7→
  8→interface Props {
  9→  data: AnalysisResult;
 10→  onBack: () => void;
 11→  user: User | null;
 12→  onDeductCredits: (amount: number) => boolean;
 13→  onSaveSolution: (analysisId: string, recId: string, solution: GeneratedSolution) => void;
 14→  initialTab?: 'details' | 'archives' | 'overview'; // Expanded type to include overview
 15→  onNewAnalysis?: () => void;
 16→}
 17→
 18→export const Results: React.FC<Props> = ({ data, onBack, user, onDeductCredits, onSaveSolution, onNewAnalysis }) => {
 19→  const [isExporting, setIsExporting] = useState(false);
 20→
 21→  const categoryScores = Object.values(data.categories) as CategoryScore[];
 22→
 23→  const handleDownloadPDF = async () => {
 24→    const element = document.getElementById('full-pdf-report');
 25→    if (!element) return;
 26→
 27→    setIsExporting(true);
 28→    try {
 29→      // Wait a moment for the hidden div to render properly
 30→      await new Promise(resolve => setTimeout(resolve, 500));
 31→
 32→      const canvas = await html2canvas(element, {
 33→        scale: 2,
 34→        useCORS: true,
 35→        logging: false,
 36→        windowWidth: 1000 // Force width to match container style
 37→      });
 38→
 39→      const imgData = canvas.toDataURL('image/jpeg', 0.95);
 40→      const pdf = new jsPDF({
 41→        orientation: 'portrait',
 42→        unit: 'mm',
 43→        format: 'a4'
 44→      });
 45→
 46→      const pdfWidth = pdf.internal.pageSize.getWidth();
 47→      const pdfHeight = pdf.internal.pageSize.getHeight();
 48→      const imgWidth = pdfWidth;
 49→      const imgHeight = (canvas.height * imgWidth) / canvas.width;
 50→      
 51→      let heightLeft = imgHeight;
 52→      let position = 0;
 53→
 54→      // First page
 55→      pdf.addImage(imgData, 'JPEG', 0, position, imgWidth, imgHeight);
 56→      heightLeft -= pdfHeight;
 57→
 58→      // Subsequent pages if content overflows
 59→      while (heightLeft > 0) {
 60→        position = heightLeft - imgHeight;
 61→        pdf.addPage();
 62→        pdf.addImage(imgData, 'JPEG', 0, position, imgWidth, imgHeight);
 63→        heightLeft -= pdfHeight;
 64→      }
 65→      
 66→      const hostname = new URL(data.url).hostname;
 67→      pdf.save(`Audit_AEO_${hostname}_${new Date().toISOString().split('T')[0]}.pdf`);
 68→    } catch (err) {
 69→      console.error('PDF Export failed', err);
 70→      alert('Erreur lors de la génération du PDF.');
 71→    } finally {
 72→      setIsExporting(false);
 73→    }
 74→  };
 75→
 76→  const handleShare = async () => {
 77→    const shareData = {
 78→      title: 'Rapport AEO - CitedBy.ai',
 79→      text: `Découvrez l'analyse AEO pour ${data.url} sur CitedBy.ai`,
 80→      url: window.location.href,
 81→    };
 82→
 83→    try {
 84→      if (navigator.share) {
 85→        await navigator.share(shareData);
 86→      } else {
 87→        await navigator.clipboard.writeText(window.location.href);
 88→        alert('Lien du rapport copié dans le presse-papier !');
 89→      }
 90→    } catch (err) {
 91→      console.error('Share failed', err);
 92→    }
 93→  };
 94→
 95→  return (
 96→    <div className="max-w-6xl mx-auto px-4 pb-20 pt-6 relative">
 97→      
 98→      {/* Header */}
 99→      <div className="flex flex-col md:flex-row items-start md:items-center justify-between mb-8 gap-6 pt-6">
100→        <div>
101→          <h1 className="text-3xl font-serif font-bold text-white mb-2">{new URL(data.url).hostname}</h1>
102→          <p className="text-gray-400 text-sm">Analysé le {new Date(data.timestamp).toLocaleDateString()} à {new Date(data.timestamp).toLocaleTimeString()}</p>
103→        </div>
104→        
105→        {onNewAnalysis && (
106→            <button 
107→                onClick={onNewAnalysis}
108→                className="flex items-center gap-2 px-5 py-2.5 bg-primary hover:bg-primaryDark text-black font-bold rounded-xl transition-all shadow-lg shadow-primary/20 hover:scale-105"
109→            >
110→                <ScanLine size={18} /> Lancer un nouvel audit
111→            </button>
112→        )}
113→      </div>
114→
115→      {/* Content - Single View (Details) */}
116→      <div className="min-h-[500px]">
117→          <div className="space-y-6 animate-in fade-in">
118→            <div className="flex justify-between items-center mb-4">
119→               <h3 className="text-lg font-medium text-white">Analyse détaillée par catégorie</h3>
120→               <div className="flex gap-3">
121→                  <button 
122→                    onClick={handleShare}
123→                    className="flex items-center gap-2 px-3 py-2 bg-purple-500/5 border border-white/10 hover:bg-purple-500/10 rounded-lg text-sm text-gray-300 transition-colors"
124→                  >
125→                    <Share2 size={16} /> Partager
126→                  </button>
127→                  <button 
128→                    onClick={handleDownloadPDF}
129→                    disabled={isExporting}
130→                    className="flex items-center gap-2 px-3 py-2 bg-primary/10 border border-primary/20 hover:bg-primary/20 rounded-lg text-sm text-primary font-medium transition-colors"
131→                  >
132→                    {isExporting ? (
133→                        <>
134→                            <div className="animate-spin h-4 w-4 border-2 border-primary border-t-transparent rounded-full"></div>
135→                            Génération...
136→                        </>
137→                    ) : (
138→                        <>
139→                            <Download size={16} /> Générer PDF Complet
140→                        </>
141→                    )}
142→                  </button>
143→               </div>
144→            </div>
145→
146→            <div className="grid md:grid-cols-2 gap-6">
147→              {categoryScores.map((cat, i) => (
148→                <CategoryCard key={i} category={cat} />
149→              ))}
150→            </div>
151→
152→            {/* --- PROFESSIONAL PDF REPORT CONTAINER (HIDDEN) --- */}
153→            <div 
154→              id="full-pdf-report" 
155→              className="bg-white text-black font-sans"
156→              style={{
157→                position: 'absolute',
158→                top: 0,
159→                left: '-9999px',
160→                width: '1000px', 
161→                padding: '60px',
162→              }}
163→            >
164→              {/* PAGE 1: COVER */}
165→              <div className="flex flex-col h-[1300px] relative border-b-2 border-gray-100 mb-10 pb-10">
166→                  {/* Header Logo */}
167→                  <div className="flex justify-between items-center mb-20">
168→                      <div className="flex items-center gap-3">
169→                          <div className="w-12 h-12 rounded bg-[#10b981] flex items-center justify-center text-white font-serif font-bold text-3xl">C</div>
170→                          <span className="font-serif text-3xl font-bold text-gray-900">CitedBy.ai</span>
171→                      </div>
172→                      <div className="text-right">
173→                          <p className="text-gray-500 text-sm">Rapport d'Audit AEO</p>
174→                          <p className="text-gray-900 font-bold">{new Date(data.timestamp).toLocaleDateString()}</p>
175→                      </div>
176→                  </div>
177→
178→                  {/* Title Section */}
179→                  <div className="text-center mt-20 mb-20">
180→                      <h1 className="text-5xl font-serif font-bold text-gray-900 mb-6 tracking-tight">Audit de Visibilité Générative</h1>
181→                      <p className="text-2xl text-gray-500">{new URL(data.url).hostname}</p>
182→                  </div>
183→
184→                  {/* Score Hero */}
185→                  <div className="flex justify-center mb-20">
186→                      <div className="relative w-64 h-64 flex items-center justify-center">
187→                          {/* We recreate a static SVG ring for PDF to avoid animation glitches */}
188→                          <svg viewBox="0 0 100 100" className="w-full h-full transform -rotate-90">
189→                              <circle cx="50" cy="50" r="45" fill="none" stroke="#f3f4f6" strokeWidth="8" />
190→                              <circle 
191→                                cx="50" 
192→                                cy="50" 
193→                                r="45" 
194→                                fill="none" 
195→                                stroke={data.globalScore >= 80 ? "#10b981" : data.globalScore >= 50 ? "#c084fc" : "#ef4444"}
196→                                strokeWidth="8" 
197→                                strokeDasharray={`${(data.globalScore / 100) * 283} 283`}
198→                                strokeLinecap="round"
199→                              />
200→                          </svg>
201→                          <div className="absolute flex flex-col items-center">
202→                              <span className="text-6xl font-bold text-gray-900">{data.globalScore}</span>
203→                              <span className="text-sm font-bold text-gray-400 uppercase tracking-widest mt-2">Score Global</span>
204→                          </div>
205→                      </div>
206→                  </div>
207→
208→                  {/* Executive Summary */}
209→                  <div className="bg-gray-50 p-8 rounded-2xl border border-gray-200 mt-auto mb-10">
210→                      <h3 className="font-bold text-gray-900 text-lg mb-4 flex items-center gap-2">
