230→                              <p className="text-lg font-bold text-gray-900">{data.categories['entity']?.score || 0}/100</p>
231→                          </div>
232→                      </div>
233→                  </div>
234→              </div>
235→
236→              {/* PAGE 2: DETAILS & RECOMMANDATIONS */}
237→              <div className="flex flex-col min-h-[1000px]">
