  1→import React, { useState, useMemo, useEffect } from 'react';
  2→import { Project, User, AnalysisResult, GeneratedSolution } from '../types';
  3→import { Plus, Search, Globe, TrendingUp, Calendar, ArrowUpRight, BarChart3, ChevronDown, Zap, Activity, ArrowRight, Wrench, FileText, Shield, ExternalLink, Clock, LayoutDashboard, Bot, Lock, ChevronLeft, ChevronRight, Eye, RefreshCw, ClipboardList, ArrowLeft, ClipboardCheck, Archive, Code } from 'lucide-react';
  4→import ScoreRing from '../components/ScoreRing';
  5→import { Results } from './Results';
  6→import ActionPlan from './ActionPlan';
  7→import GenerationModal from '../components/GenerationModal';
  8→
  9→interface ProjectsProps {
 10→  onBack: () => void;
 11→  onNavigateToAnalysis: () => void;
 12→  user: User | null;
 13→  history: AnalysisResult[];
 14→  onViewAnalysis: (result: AnalysisResult, tab: 'overview' | 'details' | 'recommendations' | 'preview') => void;
 15→  projectCount: number;
 16→  maxProjects: number;
 17→  onNavigateToPlan: () => void;
 18→  onDeductCredits: (amount: number) => boolean;
 19→  onSaveSolution: (analysisId: string, recId: string, solution: GeneratedSolution) => void;
 20→  onNewAnalysis: () => void;
 21→  onNavigateToRecharge: () => void;
 22→  initialUrl?: string;
 23→  initialTab?: string;
 24→}
 25→
 26→// Helper to convert AnalysisResult to Project format
 27→const mapAnalysisToProject = (analysis: AnalysisResult, index: number): Project => {
 28→  const hostname = new URL(analysis.url).hostname;
 29→  return {
 30→    id: `proj_${index}_${hostname}`,
 31→    name: hostname,
 32→    domain: analysis.url,
 33→    status: 'active',
 34→    lastRun: analysis.timestamp,
 35→    visibilityScore: analysis.globalScore,
 36→    trend: analysis.globalScore > 70 ? 12 : (analysis.globalScore > 50 ? 5 : -5), // Simulé basé sur le score
 37→    nextRun: new Date(new Date(analysis.timestamp).getTime() + 86400000 * 7).toISOString()
 38→  };
 39→};
 40→
 41→const Projects: React.FC<ProjectsProps> = ({ onBack, onNavigateToAnalysis, user, history, onViewAnalysis, projectCount, maxProjects, onNavigateToPlan, onDeductCredits, onSaveSolution, onNewAnalysis, onNavigateToRecharge, initialUrl, initialTab }) => {
 42→  // Navigation internal state: monitoring | report | action-plan | archives
 43→  const [activeTab, setActiveTab] = useState<'monitoring' | 'report' | 'action-plan' | 'archives'>(() => {
 44→    if (initialTab === 'archives') return 'archives';
 45→    if (initialTab === 'recommendations' || initialTab === 'action-plan') return 'action-plan';
 46→    if (initialTab === 'details' || initialTab === 'report') return 'report';
 47→    return 'monitoring';
 48→  });
 49→
 50→  useEffect(() => {
 51→    if (initialTab === 'archives') setActiveTab('archives');
 52→    else if (initialTab === 'recommendations') setActiveTab('action-plan');
 53→    else if (initialTab === 'details' || initialTab === 'report') setActiveTab('report');
 54→    else if (initialTab === 'overview') setActiveTab('monitoring');
 55→  }, [initialTab]);
 56→
 57→  // Use history to build project list, defaulting to mock if empty for demo
 58→  const projects = useMemo(() => {
 59→    if (history.length > 0) {
 60→      // Deduplicate by URL hostname, keeping the most recent
 61→      const uniqueMap = new Map<string, AnalysisResult>();
 62→      history.forEach(item => {
 63→        try {
 64→            const host = new URL(item.url).hostname;
 65→            if (!uniqueMap.has(host) || new Date(item.timestamp) > new Date(uniqueMap.get(host)!.timestamp)) {
 66→                uniqueMap.set(host, item);
 67→            }
 68→        } catch(e) {}
 69→      });
 70→      return Array.from(uniqueMap.values()).map((analysis, index) => mapAnalysisToProject(analysis, index));
 71→    } else {
 72→      // Mock data fallback if no history
 73→      return [
 74→        {
 75→          id: 'demo_1',
 76→          name: 'Exemple Site Demo',
 77→          domain: 'https://demo-site.com',
 78→          status: 'active',
 79→          lastRun: new Date().toISOString(),
 80→          visibilityScore: 45,
 81→          trend: 0,
 82→          nextRun: new Date(Date.now() + 86400000).toISOString()
 83→        }
 84→      ] as Project[];
 85→    }
 86→  }, [history]);
 87→
 88→  const [selectedProjectId, setSelectedProjectId] = useState<string>(() => {
 89→    if (initialUrl && projects.length > 0) {
 90→        try {
 91→            const targetHost = new URL(initialUrl).hostname;
 92→            // The projects mapping uses hostname as name
 93→            const found = projects.find(p => p.name === targetHost);
 94→            if (found) return found.id;
 95→        } catch(e) {}
 96→    }
 97→    return projects[0]?.id || '';
 98→  });
 99→
100→  const [selectedAnalysisState, setSelectedAnalysisState] = useState<AnalysisResult | null>(null);
101→  
102→  // States for viewing archive modal
103→  const [isModalOpen, setIsModalOpen] = useState(false);
104→  const [currentSolution, setCurrentSolution] = useState<GeneratedSolution | null>(null);
105→
106→  const currentProject = projects.find(p => p.id === selectedProjectId) || projects[0];
107→  
108→  // Filter history for current project ONLY
109→  const projectHistory = useMemo(() => {
110→    return history
111→      .filter(h => {
112→          try { return new URL(h.url).hostname === currentProject.name; }
113→          catch(e) { return false; }
114→      })
115→      .sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
116→  }, [history, currentProject]);
117→
118→  // Reset selected analysis when project changes
119→  useEffect(() => {
120→    setSelectedAnalysisState(null);
121→  }, [selectedProjectId]);
122→
123→  // The analysis to display (either user-selected from table, or the latest one)
124→  const activeAnalysis = selectedAnalysisState || projectHistory[0];
125→
126→  const handleOpenStoredSolution = (solution: GeneratedSolution) => {
127→    setCurrentSolution(solution);
128→    setIsModalOpen(true);
129→  };
130→
131→  // Calculate Pillar Scores from real categories if available
132→  const getPillarScores = () => {
133→    if (!activeAnalysis) {
134→      return {
135→        tech: 50,
136→        sem: 50,
137→        auth: 50
138→      };
139→    }
140→    
141→    const cats = activeAnalysis.categories;
142→    
143→    // Aggregation logic
144→    const techScore = Math.round(
145→      ((cats['technical']?.score || 0) + (cats['ux']?.score || 0) + (cats['freshness']?.score || 0)) / 3
146→    );
147→    
148→    const semScore = Math.round(
149→      ((cats['semantic']?.score || 0) + (cats['content']?.score || 0) + (cats['geo']?.score || 0) + (cats['media']?.score || 0)) / 4
150→    );
151→    
152→    const authScore = Math.round(
153→      ((cats['entity']?.score || 0) + (cats['structured_data']?.score || 0) + (cats['trust']?.score || 0)) / 3
154→    );
155→
156→    return { tech: techScore, sem: semScore, auth: authScore };
157→  };
158→
159→  const pillarScores = getPillarScores();
160→
161→  const getScoreColor = (score: number) => {
162→    if (score >= 80) return 'text-white'; // Purple implied by bg bar
163→    if (score >= 60) return 'text-purple-400';
164→    return 'text-blue-400'; // For variation
